Rules.InvariantScript:
If(
    IsBlank(gblEnvironmentVariables),
    Set(
        gblEnvironmentVariables,
        UKCustomsAppStart.Run()
    )
);
// if logged in user is elevated, set gblIsAdmin
If(
    IsMatch(
        gblEnvironmentVariables.elevatedusers,
        Lower(User().Email),
        MatchOptions.Contains
    ),
    Set(
        gblIsAdmin,
        true
    ),
    Set(
        gblIsAdmin,
        false
    )
);
